function uf_upload_form() {
    if (is_user_logged_in()) {
        ?>
        <form action="" method="post" enctype="multipart/form-data">
            <label for="profile_picture">Profile Picture (JPEG, PNG):</label>
            <input type="file" name="profile_picture" id="profile_picture" accept=".jpg, .jpeg, .png"><br>
            <label for="document">Document (PDF, DOC, DOCX):</label>
            <input type="file" name="document" id="document" accept=".pdf, .doc, .docx"><br>
            <input type="submit" name="uf_upload" value="Upload">
        </form>
        <?php
    } else {
        echo 'You must be logged in to upload files.';
    }
}

function uf_handle_upload() {
    if (isset($_POST['uf_upload'])) {
        $upload_dir = wp_upload_dir();
        $user_dir = $upload_dir['basedir'] . '/user-files/' . get_current_user_id();

        if (!file_exists($user_dir)) {
            wp_mkdir_p($user_dir);
        }

        foreach ($_FILES as $file) {
            if ($file['error'] == UPLOAD_ERR_OK) {
                $allowed_types = array('image/jpeg', 'image/png', 'application/pdf', 'application/msword', 'application/vnd.openxmlformats-officedocument.wordprocessingml.document');
                if (in_array($file['type'], $allowed_types)) {
                    $filename = basename($file['name']);
                    $target_file = $user_dir . '/' . $filename;

                    if (move_uploaded_file($file['tmp_name'], $target_file)) {
                        echo 'File uploaded successfully: ' . esc_html($filename);
                    } else {
                        echo 'Error uploading file.';
                    }
                } else {
                    echo 'File type not allowed.';
                }
            } else {
                echo 'File upload error.';
            }
        }
    }
}

add_action('wp', 'uf_handle_upload');
add_shortcode('uf_upload_form', 'uf_upload_form');
